**Setup (once, e.g. `tests/setup.js`):**
```js
import { beforeEach } from "vitest";

beforeEach(() => {
  document.body.innerHTML = `
    <form id="todoForm"><input id="todoInput" /></form>
    <p id="activeText"></p>
    <section id="todoList"></section>
    <button class="filter-btn active" data-filter="all"></button>
    <button class="filter-btn" data-filter="active"></button>
    <button class="filter-btn" data-filter="done"></button>
    <button id="clearCompletedBtn"></button>
    <button id="markAllBtn"></button>
  `;
  localStorage.clear();
  vi.resetModules(); // re-run app.js bootstrap fresh each test
});
```

**CRUD + persistence (`tests/todo-crud.test.js`):**
```js
import { describe, it, expect, vi } from "vitest";

describe("addTodo / toggleTodo / deleteTodo", () => {
  it("ignores whitespace-only input", async () => {
    await import("../app.js");
    document.getElementById("todoInput").value = "   ";
    document.getElementById("todoForm").dispatchEvent(new Event("submit", { bubbles: true, cancelable: true }));
    expect(document.querySelectorAll(".todo-item").length).toBe(0);
  });

  it("toggleTodo/deleteTodo on a non-existent id is a no-op", async () => {
    const mod = await import("../app.js");
    // requires exporting toggleTodo/deleteTodo, or drive via DOM as below
  });
});
```

**Error handling — storage failure (`tests/storage-errors.test.js`):**
```js
import { describe, it, expect, vi } from "vitest";

it("surfaces or survives a localStorage.setItem failure", async () => {
  vi.spyOn(Storage.prototype, "setItem").mockImplementation(() => {
    throw new DOMException("QuotaExceededError");
  });
  await import("../app.js");
  document.getElementById("todoInput").value = "buy milk";
  expect(() =>
    document.getElementById("todoForm").dispatchEvent(new Event("submit", { bubbles: true, cancelable: true }))
  ).not.toThrow(); // currently WILL throw — documents the gap
});

it("recovers from corrupted localStorage JSON", async () => {
  localStorage.setItem("simple_todos_v1", "{not valid json");
  const warn = vi.spyOn(console, "warn").mockImplementation(() => {});
  await import("../app.js");
  expect(document.querySelector(".empty")).not.toBeNull();
  warn.mockRestore();
});
```

**Filter edge case (`tests/filter.test.js`):**
```js
it("falls back to showing all todos for an unrecognized filter", async () => {
  await import("../app.js");
  // seed two todos via the form, then manually set an invalid filter
  // and call the (currently unexported) setFilter — requires export to unit test directly,
  // or simulate by dispatching click on a button with a bogus data-filter value.
});
```

**Inline edit (`tests/edit.test.js`):**
```js
it("Enter-then-blur does not double-save (finished guard)", async () => {
  await import("../app.js");
  // add a todo, dblclick its text to enter edit mode
  const text = document.querySelector(".todo-text");
  text.dispatchEvent(new MouseEvent("dblclick", { bubbles: true }));
  const input = document.querySelector(".edit-input");
  input.value = "updated";
  input.dispatchEvent(new KeyboardEvent("keydown", { key: "Enter" }));
  input.dispatchEvent(new Event("blur"));
  expect(document.querySelectorAll(".todo-text").length).toBe(1); // not duplicated/corrupted
});

it("Escape discards the edit", async () => { /* same setup, key: Escape, assert original text retained */ });
```

**Integration — bootstrap failure (`tests/bootstrap.test.js`):**
```js
it("throws clearly (or should gracefully no-op) when required DOM nodes are missing", async () => {
  document.body.innerHTML = ""; // no #todoForm etc.
  await expect(import("../app.js")).rejects.toThrow(); // documents current unguarded behavior
});
```

**Integration — cross-tab sync (`tests/cross-tab.test.js`):**
```js
it("re-renders when a storage event fires for the todos key", async () => {
  await import("../app.js");
  localStorage.setItem("simple_todos_v1", JSON.stringify([{ id: "1", text: "external", completed: false }]));
  window.dispatchEvent(new StorageEvent("storage", { key: "simple_todos_v1" }));
  expect(document.body.textContent).toContain("external");
});
```

---

**Recommendation:** the highest-leverage fix isn't writing more skeletons — it's adding `export` to the pure logic functions (`addTodo`, `toggleTodo`, `deleteTodo`, `filteredTodos`, `getActiveCount`, etc.) so they can be unit-tested directly instead of only through DOM event simulation. Want me to do that refactor and scaffold the actual Vitest config/test files, or keep this as analysis only?

